(window.webpackJsonp=window.webpackJsonp||[]).push([[18],{426:function(t,a,s){"use strict";s.r(a);var r=s(2),e=Object(r.a)({},(function(){var t=this,a=t._self._c;return a("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[a("h2",{attrs:{id:"随笔"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#随笔"}},[t._v("#")]),t._v(" 随笔")]),t._v(" "),a("h3",{attrs:{id:"引言"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#引言"}},[t._v("#")]),t._v(" 引言")]),t._v(" "),a("p",[t._v("​\t不知不觉间已经要到了本科毕业的日子了，这段时间以来一直想写些什么来对一年来的经历做一个总结。每次新建一个markdown文件之后，看着闪烁的光标不知道如何下手，今天难得有了些思绪，遂记录。")]),t._v(" "),a("h3",{attrs:{id:"回忆"}},[a("a",{staticClass:"header-anchor",attrs:{href:"#回忆"}},[t._v("#")]),t._v(" 回忆")]),t._v(" "),a("p",[t._v("​\t这一年多来经历了很多事，以流水账的形式大致记录一下一年多来的经历。")]),t._v(" "),a("p",[t._v("​\t最开始是大三的寒假，大三的寒假结束之后就要进入大三的下学期，同学们都要找自己的出路了，无论是升学或是工作。当时课程成绩还算不错，于是开始着手准备保研。当时自己只有绩点还算可以，没有参加过任何比赛也就没有比赛加分（学校保研总成绩中绩点占比90%，比赛加分占比10%），十分焦虑仅凭绩点并不能获得保研名额，于是报名了下学期的蓝桥杯和计算机设计大赛。寒假报名了y总的《算法基础课》开始学习算法，从寒假开始到蓝桥杯在各个平台上陆陆续续也做了200道左右的算法题。虽然自认为学习的不算深入，但也算是让我算法入了门，直到现在我偶尔也会去刷一些算法题，目前lc已经做了400+题目。这也算是我大学生涯中做得为数不多的称得上是有意义的事情吧。说回比赛，在做了一些准备之后蓝桥杯拿了个省二，计设也拿了省二。拿到了竞赛加分之后其实感觉已经算是比较有把握能拿到保研资格了。")]),t._v(" "),a("p",[t._v("​\t七月份各个高校陆陆续续都开通了夏令营的报名，此时成绩排名也已经公布，我大概在14%这个位置。其实这个排名报一些比本校好的学校基本没戏，但我还是在南大报名截止之前象征性了报了南大的计科专硕和软院学硕，最后也确实没有过初筛，整个夏令营只需要准备本校的面试。本校夏令营的面试刚好和暑期实践时间重叠，考虑到暑期实践会影响夏令营的复习进度，我提前一个多月就买了考研408的几本参考资料准备复习。说到这里不得不反思自己从上大学来的一个缺点。做什么事情前的规划都很充分也很提前，但是自己从来没有完整地执行过自己制定的计划，包括这次夏令营准备。于是，严格意义上来讲，我只在夏令营面试的前三天才开始着手准备面试，包括英文自我介绍、英文问题准备、项目准备以及408基础。面试的结果也很一般，其中一个老师问的三个技术问题我都不会，双方陷入了短暂而尴尬的沉默中，在我的疯狂道歉中结束了唯一的夏令营面试。好在凭借着笔试成绩勉强拿到了本校优营。")]),t._v(" "),a("p",[t._v('​\t早在六月份我就已经在物色研究生导师了，刚开始在同学的推荐下套了遥感学院的大牛cv导师，可惜因为没有相关经验直接被拒了。那段时间每天疯狂上知乎去搜索哪些研究方向有前景，哪些方向容易找工作......，最后我个人倾向于找系统和ai结合方向的导师，反正最好不是纯ai相关。某天在学校官网上看到了新入职武汉的一名老师做分布式机器学习方向，并且这位导师入职即教授而且有腾讯的工作经验，我瞬间感觉自己找到了"真爱"，于是在学长的鼓励下果断出击陶瓷，然后和老师线下交流也很顺利，暑假期间也完成了老师布置的练手小任务。')])])}),[],!1,null,null,null);a.default=e.exports}}]);